const Ucol = "#B90845"

let lineLayers = []
let borderLayers = []

function smoothPanAndZoom(lat, lng, zoomLevel) {
  map.flyTo([lat, lng], zoomLevel, {
  animate: true,
  duration: 0.3
  });
}

function addLineToMap(geojsonData, view = null, stops, lineId = null) {
  // Crée une couche de bordure noire
  const borderLayer = L.geoJSON(geojsonData, {
    style: function (feature) {
      return {
        color: 'black',
        weight: 4,
        dashArray: feature.properties.dashArray || null
      };
    },
    onEachFeature: function (feature, layer) {
      borderLayers.push(layer); // stocker les couches individuelles
    }
  }).addTo(map);

  // Crée la couche principale colorée
  const Layerdeligne = L.geoJSON(geojsonData, {
    style: function (feature) {
      return {
        color: feature.properties.color,
        weight: 4,
        dashArray: feature.properties.dashArray || null
      };
    },
    onEachFeature: function (feature, layer) {
      lineLayers.push(layer); // stocker les couches individuelles

      layer.on('click', function () {
        // Réinitialiser le style de toutes les lignes
        lineLayers.forEach(l => l.setStyle({ weight: 2 }));
        borderLayers.forEach(l => l.setStyle({ weight: 1 }));

        // Zoom/pan sur la vue spécifiée
        if (view && view.length === 3) {
          smoothPanAndZoom(view[0], view[1], view[2]);
        } else if (view && view.length === 2) {
          map.setView([view[0], view[1]], view[2] || 10);
        }

        // Mettre en avant toutes les features de cette ligne
        Layerdeligne.eachLayer(function (l) {
          l.setStyle({ weight: 5, pane: 'focusPane'});
          l.bringToFront()
        });

        // Mettre en avant les bordures de cette ligne
        borderLayer.eachLayer(function (l) {
          l.setStyle({ weight: 7 });
        });

        layer.bringToFront();

        // Supprimer anciens marqueurs
        currentMarkers.forEach(m => map.removeLayer(m));
        currentMarkers = [];

        clearMarkers();

        const color = feature.properties.color;

        if (stops) {
          addStopsToMap(stops, color);
        }

        if (lineId) openMenu(lineId);

        document.addEventListener('click', function (e) {
          const clickedElement = e.target;
        
          // Vérifie si on clique sur une tuile (image chargée par Leaflet)
          if (clickedElement.classList.contains('leaflet-tile')) {
            console.log('Clic sur une tuile de fond');
            lineLayers.forEach(l => l.setStyle({ weight: 2 }));
            borderLayers.forEach(l => l.setStyle({ weight: 1 }));
          } else {
            console.log('Clic ailleurs (UI, couche, etc.)');
          }
        });
      });
    }
  }).addTo(map);

  return Layerdeligne;
}



